// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// the current record checked is the new default ou, get it's value and set the record's default OU to it.
	var newDefaultOU = current.getValue('discover_office_hierarchy');
	// NOTE: this is run in an after update script.  If you could check the Default OU on a member 
	//       then you need to be able to reset the rest of the values.  So, this can't be a glide record secure
	//       because there may be other OUs where you don't have permission to update a memember.
	var grCurrentUserOU = new GlideRecord('x_153465_discovert_discover_office_members');
	grCurrentUserOU.addQuery('office_member', current.office_member);
	grCurrentUserOU.query();
	while(grCurrentUserOU.next()){
		if(grCurrentUserOU.getUniqueValue() != current.getUniqueValue()){
			grCurrentUserOU.u_previous_default_ou = grCurrentUserOU.u_default_ou;
			grCurrentUserOU.u_default_ou = newDefaultOU;
			grCurrentUserOU.u_isdefaultou = false;
			// STRY0057846 - improve performance by stopping additoinal processing
			grCurrentUserOU.setWorkflow(false);
			grCurrentUserOU.update();
		}
	}

})(current, previous);
